#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MaintenanceDelta {
    pub debt_score_start: f64,
    pub debt_score_end: f64,
    pub coverage_start: f64,
    pub coverage_end: f64,
    pub stale_docs_start: u32,
    pub stale_docs_end: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case", tag = "type")]
pub enum SprintHighlight {
    VelocityIncrease { percent: f64 },
    CoverageImproved { from: f64, to: f64 },
    DebtReduced { items: u32 },
    AiTasksEfficient { savings_hours: f64 },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case", tag = "type")]
pub enum SprintConcern {
    VelocityDrop { percent: f64 },
    CoverageDrop { from: f64, to: f64 },
    DebtIncreased { items: u32 },
    StaleDocsIncreased { count: u32 },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SprintAnalysis {
    pub sprint: SprintInfo,
    pub velocity: VelocityMetrics,
    pub ai_impact: AiImpactMetrics,
    pub maintenance_delta: MaintenanceDelta,
    pub highlights: Vec<SprintHighlight>,
    pub concerns: Vec<SprintConcern>,
}

pub fn analyze_sprint(project_path: &std::path::Path, sprint: SprintInfo) -> Result<SprintAnalysis> {
    let period = DateRange { start: sprint.start.clone(), end: sprint.end.clone() };
    let velocity = compute_velocity(project_path, &period)?;
    let ai_impact = compute_ai_impact(project_path, &period);

    let delta = MaintenanceDelta {
        debt_score_start: 0.0,
        debt_score_end: 0.0,
        coverage_start: 0.0,
        coverage_end: 0.0,
        stale_docs_start: 0,
        stale_docs_end: 0,
    };

    let mut highlights = Vec::new();
    let mut concerns = Vec::new();

    if velocity.commits.average_per_day > 3.0 {
        highlights.push(SprintHighlight::VelocityIncrease { percent: 10.0 });
    }
    if ai_impact.time_savings.savings_ratio > 0.5 {
        highlights.push(SprintHighlight::AiTasksEfficient {
            savings_hours: ai_impact.time_savings.estimated_manual_hours,
        });
    }
    if velocity.commits.total == 0 {
        concerns.push(SprintConcern::VelocityDrop { percent: 100.0 });
    }

    Ok(SprintAnalysis {
        sprint,
        velocity,
        ai_impact,
        maintenance_delta: delta,
        highlights,
        concerns,
    })
}

/// 直近 N スプリントを自動算出（2週間ごとのスプリント）
pub fn recent_sprints(project_path: &std::path::Path, count: u32) -> Result<Vec<SprintAnalysis>> {
    let today = chrono::Utc::now().date_naive();
    let mut results = Vec::new();
    for i in 0..count {
        let end = today - chrono::Duration::weeks(i as i64 * 2);
        let start = end - chrono::Duration::weeks(2) + chrono::Duration::days(1);
        let sprint = SprintInfo {
            name: format!("Sprint -{}", i),
            start: start.format("%Y-%m-%d").to_string(),
            end: end.format("%Y-%m-%d").to_string(),
            duration_days: 14,
        };
        if let Ok(analysis) = analyze_sprint(project_path, sprint) {
            results.push(analysis);
        }
    }
    Ok(results)
}

use serde::{Deserialize, Serialize};
use chrono::NaiveDate;
use std::collections::HashMap;
use crate::error::{AppError, Result};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DateRange {
    pub start: String, // ISO date "2026-01-01"
    pub end: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CommitMetrics {
    pub total: u32,
    pub by_author: HashMap<String, u32>,
    pub average_per_day: f64,
    pub streak_days: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CodeChangeMetrics {
    pub lines_added: u32,
    pub lines_deleted: u32,
    pub files_changed: u32,
    pub net_growth: i32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VelocityMetrics {
    pub period: DateRange,
    pub commits: CommitMetrics,
    pub code_changes: CodeChangeMetrics,
    pub daily_breakdown: Vec<DailyMetrics>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DailyMetrics {
    pub date: String,
    pub commits: u32,
    pub lines_added: u32,
    pub lines_deleted: u32,
}

pub fn compute_velocity(project_path: &std::path::Path, period: &DateRange) -> Result<VelocityMetrics> {
    let repo = git2::Repository::open(project_path)
        .map_err(|e| AppError::Git(e.to_string()))?;

    let start = NaiveDate::parse_from_str(&period.start, "%Y-%m-%d")
        .map_err(|e| AppError::Validation(e.to_string()))?;
    let end = NaiveDate::parse_from_str(&period.end, "%Y-%m-%d")
        .map_err(|e| AppError::Validation(e.to_string()))?;

    let mut revwalk = repo.revwalk().map_err(|e| AppError::Git(e.to_string()))?;
    revwalk.push_head().ok();

    let mut total_commits = 0u32;
    let mut by_author: HashMap<String, u32> = HashMap::new();
    let mut lines_added = 0u32;
    let mut lines_deleted = 0u32;
    let mut files_changed_set = std::collections::HashSet::new();
    let mut daily: HashMap<String, DailyMetrics> = HashMap::new();
    let mut commit_dates = std::collections::HashSet::new();

    for oid_result in revwalk {
        let Ok(oid) = oid_result else { continue };
        let Ok(commit) = repo.find_commit(oid) else { continue };

        let ts = commit.time().seconds();
        let dt = chrono::DateTime::from_timestamp(ts, 0)
            .unwrap_or_default()
            .naive_utc()
            .date();

        if dt < start || dt > end {
            continue;
        }

        total_commits += 1;
        let author = commit.author().name().unwrap_or("unknown").to_string();
        *by_author.entry(author).or_insert(0) += 1;

        let date_str = dt.format("%Y-%m-%d").to_string();
        commit_dates.insert(date_str.clone());

        // Diff stats
        let (added, deleted, files) = if let Ok(parent) = commit.parent(0) {
            if let (Ok(t1), Ok(t2)) = (commit.tree(), parent.tree()) {
                if let Ok(diff) = repo.diff_tree_to_tree(Some(&t2), Some(&t1), None) {
                    let (ins, del) = if let Ok(stats) = diff.stats() {
                        (stats.insertions() as u32, stats.deletions() as u32)
                    } else {
                        (0, 0)
                    };
                    let mut fset = std::collections::HashSet::new();
                    diff.foreach(
                        &mut |d, _| {
                            if let Some(p) = d.new_file().path() {
                                fset.insert(p.to_string_lossy().to_string());
                            }
                            true
                        },
                        None,
                        None,
                        None,
                    )
                    .ok();
                    (ins, del, fset)
                } else {
                    (0, 0, std::collections::HashSet::new())
                }
            } else {
                (0, 0, std::collections::HashSet::new())
            }
        } else {
            (0, 0, std::collections::HashSet::new())
        };

        lines_added += added;
        lines_deleted += deleted;
        files_changed_set.extend(files);

        let entry = daily.entry(date_str.clone()).or_insert(DailyMetrics {
            date: date_str,
            commits: 0,
            lines_added: 0,
            lines_deleted: 0,
        });
        entry.commits += 1;
        entry.lines_added += added;
        entry.lines_deleted += deleted;
    }

    // Streak: consecutive days with commits
    let streak_days = compute_streak(&commit_dates, &end);

    let days = ((end - start).num_days() + 1).max(1) as f64;
    let avg_per_day = total_commits as f64 / days;

    let mut daily_vec: Vec<DailyMetrics> = daily.into_values().collect();
    daily_vec.sort_by(|a, b| a.date.cmp(&b.date));

    Ok(VelocityMetrics {
        period: period.clone(),
        commits: CommitMetrics {
            total: total_commits,
            by_author,
            average_per_day: avg_per_day,
            streak_days,
        },
        code_changes: CodeChangeMetrics {
            lines_added,
            lines_deleted,
            files_changed: files_changed_set.len() as u32,
            net_growth: lines_added as i32 - lines_deleted as i32,
        },
        daily_breakdown: daily_vec,
    })
}

fn compute_streak(commit_dates: &std::collections::HashSet<String>, end: &NaiveDate) -> u32 {
    let mut streak = 0u32;
    let mut current = *end;
    loop {
        let s = current.format("%Y-%m-%d").to_string();
        if commit_dates.contains(&s) {
            streak += 1;
            if let Some(prev) = current.pred_opt() {
                current = prev;
            } else {
                break;
            }
        } else {
            break;
        }
    }
    streak
}

use serde::{Deserialize, Serialize};
use uuid::Uuid;
use chrono::Utc;
use crate::error::{AppError, Result};

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum KnowledgeType {
    DesignDecision,
    RetroLearning,
    TechNote,
    Postmortem,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Comment {
    pub id: String,
    pub author: String,
    pub content: String,
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct KnowledgeEntry {
    pub id: String,
    pub entry_type: KnowledgeType,
    pub title: String,
    pub content: String,
    pub author: String,
    pub product_id: String,
    pub linked_docs: Vec<String>,
    pub tags: Vec<String>,
    pub created_at: String,
    pub comments: Vec<Comment>,
}

pub struct KnowledgeStore {
    path: std::path::PathBuf,
}

impl KnowledgeStore {
    pub fn new(project_path: &std::path::Path) -> Self {
        Self { path: project_path.join(".devnest").join("knowledge.json") }
    }

    pub fn load_all(&self) -> Vec<KnowledgeEntry> {
        let content = std::fs::read_to_string(&self.path).unwrap_or_default();
        serde_json::from_str(&content).unwrap_or_default()
    }

    pub fn save_all(&self, entries: &[KnowledgeEntry]) -> Result<()> {
        if let Some(parent) = self.path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let json = serde_json::to_string_pretty(entries)
            .map_err(|e| AppError::Internal(e.to_string()))?;
        std::fs::write(&self.path, json)?;
        Ok(())
    }

    pub fn add_entry(&self, entry: KnowledgeEntry) -> Result<KnowledgeEntry> {
        let mut entries = self.load_all();
        entries.push(entry.clone());
        self.save_all(&entries)?;
        Ok(entry)
    }

    pub fn add_comment(&self, entry_id: &str, author: &str, content: &str) -> Result<KnowledgeEntry> {
        let mut entries = self.load_all();
        let entry = entries.iter_mut().find(|e| e.id == entry_id)
            .ok_or_else(|| AppError::NotFound(format!("Knowledge entry {} not found", entry_id)))?;
        entry.comments.push(Comment {
            id: Uuid::new_v4().to_string(),
            author: author.to_string(),
            content: content.to_string(),
            created_at: Utc::now().to_rfc3339(),
        });
        let result = entry.clone();
        self.save_all(&entries)?;
        Ok(result)
    }

    pub fn search(&self, query: &str) -> Vec<KnowledgeEntry> {
        let q = query.to_lowercase();
        self.load_all().into_iter().filter(|e| {
            e.title.to_lowercase().contains(&q)
                || e.content.to_lowercase().contains(&q)
                || e.tags.iter().any(|t| t.to_lowercase().contains(&q))
        }).collect()
    }
}

