/// code_save_progress イベントのペイロード
#[derive(Debug, Clone, Serialize)]
pub struct CodeSaveProgressPayload {
    pub path: String,
    pub status: String, // "committing" | "pushing" | "synced" | "push_failed"
    pub sha: Option<String>,
}

/// デフォルト除外ディレクトリ・ファイル
const EXCLUDE_DIRS: &[&str] = &[
    "node_modules", "target", ".git", ".next", "dist", "build",
    "__pycache__", ".cache", "vendor", "gen",
];
const EXCLUDE_FILES: &[&str] = &[".DS_Store", "Thumbs.db"];

/// コードビューアで対応する拡張子
const CODE_EXTENSIONS: &[&str] = &[
    "ts", "tsx", "js", "jsx", "rs", "html", "htm",
    "css", "scss", "sass", "sql", "json", "toml", "yaml", "yml",
    "go", "php", "py", "md", "txt", "sh", "bash", "zsh",
    "env", "gitignore", "lock",
];

fn is_excluded_dir(name: &str) -> bool {
    EXCLUDE_DIRS.iter().any(|d| *d == name)
}

fn is_excluded_file(name: &str) -> bool {
    EXCLUDE_FILES.iter().any(|f| *f == name)
        || name.starts_with('.')
}

fn build_tree(dir: &std::path::Path, root: &std::path::Path) -> Vec<FileNode> {
    let entries = match std::fs::read_dir(dir) {
        Ok(e) => e,
        Err(_) => return vec![],
    };

    let mut nodes: Vec<FileNode> = entries
        .filter_map(|e| e.ok())
        .filter_map(|entry| {
            let path = entry.path();
            let name = entry.file_name().to_string_lossy().to_string();

            if path.is_dir() {
                if is_excluded_dir(&name) {
                    return None;
                }
                let children = build_tree(&path, root);
                // 空ディレクトリは除外
                if children.is_empty() {
                    return None;
                }
                let rel = path.strip_prefix(root).unwrap_or(&path)
                    .to_string_lossy().to_string();
                Some(FileNode {
                    name,
                    path: rel,
                    is_dir: true,
                    size: None,
                    ext: None,
                    children: Some(children),
                })
            } else {
                if is_excluded_file(&name) {
                    return None;
                }
                // コード対応拡張子のみ表示
                let ext = path.extension()
                    .and_then(|e| e.to_str())
                    .map(|s| s.to_lowercase());
                let ext_str = ext.as_deref().unwrap_or("");
                // 拡張子なしのファイル（Makefile, Dockerfile 等）も許容
                let is_code = ext.is_none()
                    || CODE_EXTENSIONS.contains(&ext_str);
                if !is_code {
                    return None;
                }
                let size = path.metadata().ok().map(|m| m.len());
                let rel = path.strip_prefix(root).unwrap_or(&path)
                    .to_string_lossy().to_string();
                Some(FileNode {
                    name,
                    path: rel,
                    is_dir: false,
                    size,
                    ext,
                    children: None,
                })
            }
        })
        .collect();

    // ディレクトリ優先、同種はアルファベット順
    nodes.sort_by(|a, b| {
        b.is_dir.cmp(&a.is_dir).then(a.name.cmp(&b.name))
    });
    nodes
}

/// リポジトリのファイルツリーを返す（node_modules / target / .git 等を除外）。
#[tauri::command]
pub async fn file_tree(
    project_id: i64,
    state: State<'_, AppState>,
) -> std::result::Result<Vec<FileNode>, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let local_path = project.local_path.clone();

    let nodes = tokio::task::spawn_blocking(move || {
        let root = std::path::Path::new(&local_path);
        build_tree(root, root)
    })
    .await
    .map_err(|e| AppError::Internal(e.to_string()))?;

    Ok(nodes)
}

/// 指定パスのファイルを読み込んで返す。
/// max_lines を超える場合は truncated: true で先頭のみ返す。
#[tauri::command]
pub async fn file_read(
    project_id: i64,
    path: String,
    max_lines: Option<u32>,
    state: State<'_, AppState>,
) -> std::result::Result<FileContent, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let local_path = project.local_path.clone();
    let limit = max_lines.unwrap_or(1000);

    // パストラバーサル防止
    if path.contains("..") {
        return Err(AppError::Validation("不正なパスです".to_string()));
    }

    tokio::task::spawn_blocking(move || {
        let abs = std::path::Path::new(&local_path).join(&path);
        if !abs.exists() {
            return Err(AppError::NotFound(format!("file: {}", path)));
        }

        // バイナリチェック（先頭 512 バイトに NUL があればバイナリ）
        let raw = std::fs::read(&abs)
            .map_err(|e| AppError::Io(format!("読み込み失敗: {}", e)))?;
        if raw[..raw.len().min(512)].contains(&0u8) {
            return Err(AppError::Validation(
                "バイナリファイルは表示できません".to_string(),
            ));
        }

        let text = String::from_utf8_lossy(&raw).to_string();
        let all_lines: Vec<&str> = text.lines().collect();
        let total_lines = all_lines.len() as u32;
        let truncated = total_lines > limit;
        let content = if truncated {
            all_lines[..limit as usize].join("\n")
        } else {
            text
        };

        Ok(FileContent { path, content, truncated, total_lines })
    })
    .await
    .map_err(|e| AppError::Internal(e.to_string()))?
}

/// コードファイルを保存し、git commit & push する。
/// commit メッセージ: "src: update {filename}"
#[tauri::command]
pub async fn file_save(
    project_id: i64,
    path: String,
    content: String,
    app_handle: AppHandle,
    state: State<'_, AppState>,
) -> std::result::Result<CodeSaveResult, AppError> {
    // パストラバーサル防止
    if path.contains("..") {
        return Err(AppError::Validation("不正なパスです".to_string()));
    }

    let project = db::project::find(&state.db, project_id).await?;
    let local_path = project.local_path.clone();

    let filename = std::path::Path::new(&path)
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or(&path)
        .to_string();
    let commit_msg = format!("src: update {}", filename);

    let _ = app_handle.emit("code_save_progress", CodeSaveProgressPayload {
        path: path.clone(),
        status: "committing".to_string(),
        sha: None,
    });

    let path_clone = path.clone();
    let (commit_sha, branch) = tokio::task::spawn_blocking(move || {
        let svc = GitService::open(&local_path)?;
        let sha = svc.write_and_commit(&path_clone, &content, &commit_msg)?;
        let branch = svc.current_branch().unwrap_or_else(|_| "main".to_string());
        Ok::<_, AppError>((sha, branch))
    })
    .await
    .map_err(|e| AppError::Internal(e.to_string()))??;

    // push（auto モードかつトークンがある場合）
    if project.sync_mode == "auto" {
        let _ = app_handle.emit("code_save_progress", CodeSaveProgressPayload {
            path: path.clone(),
            status: "pushing".to_string(),
            sha: Some(commit_sha.clone()),
        });

        // Keychain → DB フォールバックでトークン取得
        let token_result = tokio::task::spawn_blocking(move || keychain::require_token(project_id))
            .await
            .ok()
            .and_then(|r| r.ok());

        let token = if let Some(t) = token_result {
            Some(t)
        } else {
            // DB フォールバック
            let key = format!("github.token.{}", project_id);
            sqlx::query_scalar::<_, String>(
                "SELECT value FROM app_settings WHERE key = ?"
            )
            .bind(&key)
            .fetch_optional(&state.db)
            .await
            .ok()
            .flatten()
            .and_then(|v| serde_json::from_str::<String>(&v).ok())
        };

        if let Some(tok) = token {
            let local_path2 = project.local_path.clone();
            let branch2 = branch.clone();
            let sha2 = commit_sha.clone();
            let path2 = path.clone();
            let app2 = app_handle.clone();
            let push_result = tokio::task::spawn_blocking(move || {
                let svc = GitService::open(&local_path2)?;
                let mut attempt = 0u32;
                loop {
                    match svc.push(&tok, "origin", &branch2) {
                        Ok(()) => return Ok(()),
                        Err(e) if attempt < 3 => {
                            attempt += 1;
                            std::thread::sleep(std::time::Duration::from_secs(2u64.pow(attempt - 1)));
                        }
                        Err(e) => return Err(e),
                    }
                }
            })
            .await
            .map_err(|e| AppError::Internal(e.to_string()))?;

            match push_result {
                Ok(()) => {
                    let _ = app_handle.emit("code_save_progress", CodeSaveProgressPayload {
                        path: path.clone(),
                        status: "synced".to_string(),
                        sha: Some(commit_sha.clone()),
                    });
                    return Ok(CodeSaveResult { sha: commit_sha, push_status: "synced".to_string() });
                }
                Err(e) => {
                    let _ = app_handle.emit("code_save_progress", CodeSaveProgressPayload {
                        path: path.clone(),
                        status: "push_failed".to_string(),
                        sha: Some(commit_sha.clone()),
                    });
                    return Ok(CodeSaveResult { sha: commit_sha, push_status: "push_failed".to_string() });
                }
            }
        }
    }

    let _ = app_handle.emit("code_save_progress", CodeSaveProgressPayload {
        path: path.clone(),
        status: "synced".to_string(),
        sha: Some(commit_sha.clone()),
    });
    Ok(CodeSaveResult { sha: commit_sha, push_status: "pending_push".to_string() })
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    fn make_tree(dir: &TempDir) -> Vec<FileNode> {
        let root = dir.path();
        std::fs::create_dir_all(root.join("src")).unwrap();
        std::fs::write(root.join("src/main.rs"), "fn main() {}").unwrap();
        std::fs::write(root.join("src/lib.rs"), "pub mod foo;").unwrap();
        std::fs::create_dir_all(root.join("node_modules/foo")).unwrap();
        std::fs::write(root.join("node_modules/foo/index.js"), "").unwrap();
        std::fs::write(root.join("Cargo.toml"), "[package]").unwrap();
        build_tree(root, root)
    }

    #[test]
    fn test_node_modules_excluded() {
        let dir = TempDir::new().unwrap();
        let nodes = make_tree(&dir);
        assert!(!nodes.iter().any(|n| n.name == "node_modules"),
            "node_modules は除外されるべき");
    }

    #[test]
    fn test_src_dir_included() {
        let dir = TempDir::new().unwrap();
        let nodes = make_tree(&dir);
        assert!(nodes.iter().any(|n| n.name == "src" && n.is_dir),
            "src ディレクトリは含まれるべき");
    }

    #[test]
    fn test_dirs_before_files() {
        let dir = TempDir::new().unwrap();
        let nodes = make_tree(&dir);
        // ディレクトリが先に来る
        let first_file_pos = nodes.iter().position(|n| !n.is_dir).unwrap_or(nodes.len());
        let last_dir_pos = nodes.iter().rposition(|n| n.is_dir).unwrap_or(0);
        assert!(last_dir_pos < first_file_pos || first_file_pos == nodes.len(),
            "ディレクトリはファイルより前に来るべき");
    }

    #[test]
    fn test_children_populated_for_dirs() {
        let dir = TempDir::new().unwrap();
        let nodes = make_tree(&dir);
        let src = nodes.iter().find(|n| n.name == "src").unwrap();
        let children = src.children.as_ref().unwrap();
        assert_eq!(children.len(), 2, "src 配下に2ファイル");
        assert!(children.iter().any(|c| c.name == "main.rs"));
        assert!(children.iter().any(|c| c.name == "lib.rs"));
    }
}

use tauri::{AppHandle, Emitter, State};
use tauri_plugin_opener::OpenerExt;
use crate::error::AppError;
use crate::services::{github::GitHubClient, keychain, oauth};
use crate::state::AppState;

const GITHUB_CLIENT_ID_KEY: &str = "github.client_id";
const GITHUB_CLIENT_SECRET_KEY: &str = "github.client_secret";

/// DB の app_settings から JSON クォート付き文字列を取得してクォートを除去する。
async fn get_setting_plain(db: &sqlx::SqlitePool, key: &str) -> Option<String> {
    let row: Option<(String,)> = sqlx::query_as(
        "SELECT value FROM app_settings WHERE key = ?",
    )
    .bind(key)
    .fetch_optional(db)
    .await
    .ok()
    .flatten();
    row.map(|(v,)| v.trim_matches('"').to_string())
}

/// GitHub OAuth 認証フローを開始する。
/// ブラウザで認証 URL を開き、バックグラウンドでコールバックを待ってトークンを保存する。
#[tauri::command]
pub async fn github_auth_start(
    project_id: i64,
    app: AppHandle,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    let client_id = get_setting_plain(&state.db, GITHUB_CLIENT_ID_KEY)
        .await
        .ok_or_else(|| AppError::Validation("GitHub Client ID が設定されていません。Settings で OAuth App のクライアント ID を設定してください。".to_string()))?;

    if client_id.is_empty() {
        return Err(AppError::Validation(
            "GitHub Client ID が設定されていません。Settings で OAuth App のクライアント ID を設定してください。".to_string(),
        ));
    }

    // 前回のコールバックサーバータスクを中断（ポート解放）
    {
        let mut guard = state.oauth_task.lock()
            .map_err(|_| AppError::Internal("oauth_task lock poisoned".to_string()))?;
        if let Some(handle) = guard.take() {
            handle.abort();
        }
    }
    // ポートが解放されるまで少し待つ
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;

    let url = oauth::auth_url(&client_id);

    app.opener()
        .open_url(&url, None::<&str>)
        .map_err(|e| AppError::Internal(format!("ブラウザ起動失敗: {}", e)))?;

    let state_db = state.db.clone();
    let oauth_task_arc = state.oauth_task.clone();
    let handle = tokio::spawn(async move {
        let (tx, rx) = tokio::sync::oneshot::channel::<String>();

        if let Err(e) = oauth::wait_for_callback(tx).await {
            let _ = app.emit("github_auth_done", serde_json::json!({
                "success": false,
                "error": e.to_string()
            }));
            return;
        }

        let code = match rx.await {
            Ok(c) => c,
            Err(_) => {
                let _ = app.emit("github_auth_done", serde_json::json!({
                    "success": false,
                    "error": "コールバック受信に失敗しました"
                }));
                return;
            }
        };

        let secret = get_setting_plain(&state_db, GITHUB_CLIENT_SECRET_KEY)
            .await
            .unwrap_or_default();

        let client = GitHubClient::new("", "", "");
        match client.exchange_code(&code, &client_id, &secret).await {
            Ok(token) => {
                // Keychain は blocking API のため spawn_blocking でラップ
                let token_clone = token.clone();
                let keychain_result = tokio::task::spawn_blocking(move || {
                    keychain::set_token(project_id, &token_clone)
                }).await;

                // DB にもバックアップ保存（Keychain が失敗した場合のフォールバック）
                let key = format!("github.token.{}", project_id);
                let now = chrono::Utc::now().to_rfc3339();
                let _ = sqlx::query(
                    "INSERT INTO app_settings (key, value, updated_at) VALUES (?, ?, ?)
                     ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = excluded.updated_at"
                )
                .bind(&key)
                .bind(serde_json::json!(token).to_string())
                .bind(&now)
                .execute(&state_db)
                .await;

                match keychain_result {
                    Ok(Ok(())) | Ok(Err(_)) => {
                        // Keychain 成否に関わらず DB に保存済みなので成功扱い
                        let _ = app.emit("github_auth_done", serde_json::json!({
                            "success": true
                        }));
                    }
                    Err(e) => {
                        let _ = app.emit("github_auth_done", serde_json::json!({
                            "success": false,
                            "error": format!("spawn_blocking 失敗: {}", e)
                        }));
                    }
                }
            }
            Err(e) => {
                let _ = app.emit("github_auth_done", serde_json::json!({
                    "success": false,
                    "error": e.to_string()
                }));
            }
        }
        // タスク完了後にハンドルをクリア
        if let Ok(mut g) = oauth_task_arc.lock() {
            *g = None;
        }
    });

    // ハンドルを AppState に保存（次回の abort 用）
    {
        let mut guard = state.oauth_task.lock()
            .map_err(|_| AppError::Internal("oauth_task lock poisoned".to_string()))?;
        *guard = Some(handle.abort_handle());
    }

    Ok(())
}

/// コールバックで受け取った code を token に交換して Keychain に保存する。
#[tauri::command]
pub async fn github_auth_complete(
    project_id: i64,
    code: String,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    let client_id = get_setting_plain(&state.db, GITHUB_CLIENT_ID_KEY)
        .await
        .ok_or_else(|| AppError::Validation("GitHub Client ID が設定されていません".to_string()))?;

    let client_secret = get_setting_plain(&state.db, GITHUB_CLIENT_SECRET_KEY)
        .await
        .unwrap_or_default();

    let client = GitHubClient::new("", "", "");
    let token = client.exchange_code(&code, &client_id, &client_secret).await?;
    keychain::set_token(project_id, &token).map_err(|e| AppError::Keychain(e.to_string()))?;

    Ok(())
}

/// DB から GitHub トークンを取得する（Keychain フォールバック用）
async fn get_token_from_db(db: &sqlx::SqlitePool, project_id: i64) -> Option<String> {
    let key = format!("github.token.{}", project_id);
    let row: Option<(String,)> = sqlx::query_as(
        "SELECT value FROM app_settings WHERE key = ?"
    )
    .bind(&key)
    .fetch_optional(db)
    .await
    .ok()
    .flatten();
    row.map(|(v,)| v.trim_matches('"').to_string())
        .filter(|s| !s.is_empty())
}

/// 現在の GitHub 認証状態を返す。
#[tauri::command]
pub async fn github_auth_status(
    project_id: i64,
    state: State<'_, AppState>,
) -> std::result::Result<crate::services::github::GitHubAuthStatus, AppError> {
    // Keychain を試み、失敗したら DB フォールバック
    let token_opt = tokio::task::spawn_blocking(move || keychain::get_token(project_id))
        .await
        .ok()
        .and_then(|r| r.ok())
        .flatten();
    let token_opt = if token_opt.is_some() {
        token_opt
    } else {
        get_token_from_db(&state.db, project_id).await
    };
    match token_opt {
        Some(token) => {
            let client = GitHubClient::new(&token, "", "");
            match client.get_user().await {
                Ok(user) => Ok(crate::services::github::GitHubAuthStatus {
                    connected: true,
                    user_login: Some(user.login),
                    avatar_url: Some(user.avatar_url),
                }),
                Err(_) => Ok(crate::services::github::GitHubAuthStatus {
                    connected: false,
                    user_login: None,
                    avatar_url: None,
                }),
            }
        }
        _ => Ok(crate::services::github::GitHubAuthStatus {
            connected: false,
            user_login: None,
            avatar_url: None,
        }),
    }
}

/// GitHub 認証を取り消す（Keychain + DB からトークン削除）。
/// ポーリングを停止して孤立タスクを防ぐ。
#[tauri::command]
pub async fn github_auth_revoke(
    project_id: i64,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    // 認証解除時はポーリングを停止（孤立タスク防止）
    state.polling_active.store(false, std::sync::atomic::Ordering::Relaxed);
    // Keychain から削除（エラーは無視）
    let _ = keychain::delete_token(project_id);
    // DB からも削除
    let key = format!("github.token.{}", project_id);
    let _ = sqlx::query("DELETE FROM app_settings WHERE key = ?")
        .bind(&key)
        .execute(&state.db)
        .await;
    Ok(())
}

