// ─── T-R-D06: issue_draft_generate ──────────────────────────────────────────

/// issue_draft_chunk イベントのペイロード
#[derive(Debug, Clone, serde::Serialize)]
pub struct DraftChunkPayload {
    pub draft_id: i64,
    pub delta: String,
}

/// issue_draft_generate_done イベントのペイロード
#[derive(Debug, Clone, serde::Serialize)]
pub struct DraftGenerateDonePayload {
    pub draft_id: i64,
    pub draft_body: String,
}

/// Anthropic API で Issue 本文をストリーミング生成する。
/// - `issue_draft_chunk` イベントで delta を都度 emit
/// - 完了後 draft_body を DB に保存して `issue_draft_generate_done` を emit
#[tauri::command]
pub async fn issue_draft_generate(
    draft_id: i64,
    app: AppHandle,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    // ドラフトと Anthropic API キーを取得
    let draft = db::issue::draft_find(&state.db, draft_id).await?;

    let api_key_row: Option<(String,)> = sqlx::query_as(
        "SELECT value FROM app_settings WHERE key = 'anthropic.api_key'",
    )
    .fetch_optional(&state.db)
    .await?;
    let api_key = api_key_row
        .map(|(v,)| v.trim_matches('"').to_string())
        .ok_or_else(|| AppError::Validation("Anthropic API キーが設定されていません".to_string()))?;
    if api_key.is_empty() {
        return Err(AppError::Validation(
            "Anthropic API キーが設定されていません。Settings で API キーを設定してください。".to_string(),
        ));
    }

    // 関連ドキュメント一覧
    let links = db::issue::link_list(&state.db, draft_id).await.unwrap_or_default();
    let doc_context = links
        .iter()
        .filter_map(|l| l.path.as_deref())
        .collect::<Vec<_>>()
        .join(", ");

    // プロンプト構築
    let system_prompt = "あなたは GitHub Issue の作成を支援するアシスタントです。\
        ユーザーの指示に従い、明確で構造化された Issue 本文を Markdown で生成してください。";

    let user_content = format!(
        "以下の情報をもとに、GitHub Issue の本文を生成してください。\n\n\
        タイトル: {}\n\
        コンテキスト: {}\n\
        関連ドキュメント: {}\n\n\
        ## 要求\n\
        - ## 概要、## 詳細、## 再現手順（バグの場合）、## 期待する動作 のセクションを含める\
        - Markdown 形式で出力する",
        draft.title,
        draft.wizard_context.as_deref().unwrap_or("（なし）"),
        if doc_context.is_empty() { "（なし）".to_string() } else { doc_context },
    );

    // DEVNEST_TEST_MODE が設定されている場合は固定レスポンスを返す
    let mut full_body = String::new();

    if std::env::var("DEVNEST_TEST_MODE").is_ok() {
        let mock_chunks = [
            "## 概要\n\n",
            &format!("{} に関する Issue です。\n\n", draft.title),
            "## 詳細\n\n",
            "テストモードにより自動生成されたモックレスポンスです。\n\n",
            "## 期待する動作\n\n",
            "正常に動作すること。\n",
        ];
        for chunk in &mock_chunks {
            full_body.push_str(chunk);
            let _ = app.emit(
                "issue_draft_chunk",
                DraftChunkPayload { draft_id, delta: chunk.to_string() },
            );
        }
    } else {
        // Anthropic Messages API リクエスト（streaming）
        let http = reqwest::Client::new();
        let resp = http
            .post("https://api.anthropic.com/v1/messages")
            .header("x-api-key", &api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&serde_json::json!({
                "model": "claude-sonnet-4-6",
                "max_tokens": 2048,
                "stream": true,
                "system": system_prompt,
                "messages": [{ "role": "user", "content": user_content }]
            }))
            .send()
            .await
            .map_err(|e| AppError::Anthropic(e.to_string()))?;

        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().await.unwrap_or_default();
            return Err(AppError::Anthropic(format!("API エラー {}: {}", status, body)));
        }

        // SSE ストリームを処理
        use eventsource_stream::Eventsource;
        use futures_util::StreamExt;

        let mut stream = resp.bytes_stream().eventsource();

        while let Some(event) = stream.next().await {
            let event = event.map_err(|e| AppError::Anthropic(e.to_string()))?;

            if event.event == "message_stop" {
                break;
            }
            if event.event != "content_block_delta" {
                continue;
            }

            // {"type":"content_block_delta","index":0,"delta":{"type":"text_delta","text":"..."}}
            let val: serde_json::Value = serde_json::from_str(&event.data)
                .unwrap_or(serde_json::Value::Null);
            let delta = val
                .get("delta")
                .and_then(|d| d.get("text"))
                .and_then(|t| t.as_str())
                .unwrap_or("");

            if !delta.is_empty() {
                full_body.push_str(delta);
                let _ = app.emit(
                    "issue_draft_chunk",
                    DraftChunkPayload { draft_id, delta: delta.to_string() },
                );
            }
        }
    }

    // DB に draft_body を保存
    let patch = IssueDraftPatch {
        id: draft_id,
        title: None,
        body: None,
        draft_body: Some(full_body.clone()),
        wizard_context: None,
        labels: None,
        assignee_login: None,
        status: None,
        github_issue_id: None,
    };
    db::issue::draft_update(&state.db, &patch).await?;

    let _ = app.emit(
        "issue_draft_generate_done",
        DraftGenerateDonePayload { draft_id, draft_body: full_body },
    );

    Ok(())
}

// ─── T-R-D07: issue_create ───────────────────────────────────────────────────

/// AI Wizard ドラフトから GitHub Issue を作成し、DB に upsert して返す。
/// ドラフトの status を "submitted"、github_issue_id を更新する。
#[tauri::command]
pub async fn issue_create(
    draft_id: i64,
    state: State<'_, AppState>,
) -> std::result::Result<Issue, AppError> {
    // ドラフト取得
    let draft = db::issue::draft_find(&state.db, draft_id).await?;

    // プロジェクト情報・トークン取得
    let project = db::project::find(&state.db, draft.project_id).await?;
    let token = keychain::require_token(draft.project_id)?;

    // 本文は draft_body 優先、なければ body
    let body = draft.draft_body.as_deref().unwrap_or(&draft.body);

    // labels JSON 配列をパース
    let labels: Vec<String> = serde_json::from_str(&draft.labels).unwrap_or_default();

    // GitHub API で Issue 作成
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);
    let gh_issue = client
        .create_issue(&draft.title, body, &labels, draft.assignee_login.as_deref())
        .await?;

    // DB に upsert
    let now = Utc::now().to_rfc3339();
    let issue_db_id = db::issue::upsert(&state.db, draft.project_id, &gh_issue, &now).await?;

    // ドラフト status を submitted に更新
    let patch = IssueDraftPatch {
        id: draft_id,
        title: None,
        body: None,
        draft_body: None,
        wizard_context: None,
        labels: None,
        assignee_login: None,
        status: Some("submitted".to_string()),
        github_issue_id: Some(gh_issue.id),
    };
    db::issue::draft_update(&state.db, &patch).await?;

    // 作成した Issue を返す
    db::issue::find_by_id(&state.db, issue_db_id).await
}

