/// テスト・デモ用：通知を手動作成する
#[allow(clippy::too_many_arguments)]
#[tauri::command]
pub async fn notification_push(
    project_id: i64,
    event_type: String,
    title: String,
    body: Option<String>,
    dest_screen: Option<String>,
    dest_resource_id: Option<i64>,
    state: State<'_, AppState>,
    app: tauri::AppHandle,
) -> Result<i64> {
    let n = NewNotification {
        project_id,
        event_type,
