// ─── pr_add_comment ──────────────────────────────────────────────────────────

/// PR にインラインコメントをローカル保存し、GitHub に非同期投稿する。
#[tauri::command]
pub async fn pr_add_comment(
    project_id: i64,
    pr_id: i64,
    body: String,
    path: Option<String>,
    line: Option<i64>,
    state: State<'_, AppState>,
) -> std::result::Result<PrComment, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let pr = db::pr::find(&state.db, pr_id).await?;
    let token = keychain::require_token(project_id)?;
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);

    // author_login を GitHub API から取得
    let author = client
        .get_user()
        .await
        .map(|u| u.login)
        .unwrap_or_else(|_| "unknown".to_string());

    // ローカル保存（pending）
    let comment = db::pr::add_comment(
        &state.db,
        pr_id,
        &body,
        path.as_deref(),
        line,
        &author,
    )
    .await?;

    // GitHub に非同期投稿（失敗しても pending のまま残す）
    let comment_id = comment.id;
    let db_clone = state.db.clone();
    let gh_number = pr.github_number;
    tokio::spawn(async move {
        if let Ok(gh_comment_id) = client.add_issue_comment(gh_number, &body).await {
            let _ = db::pr::mark_comment_synced(&db_clone, comment_id, gh_comment_id).await;
        }
    });

    Ok(comment)
}

// ─── pr_review_submit ────────────────────────────────────────────────────────

/// PR にレビューを提出する（approve / changes_requested）。
#[tauri::command]
pub async fn pr_review_submit(
    project_id: i64,
    payload: ReviewSubmitPayload,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let pr = db::pr::find(&state.db, payload.pr_id).await?;
    let token = keychain::require_token(project_id)?;
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);

    // GitHub API の event は大文字
    let event = match payload.state.as_str() {
        "approved" => "APPROVE",
        "changes_requested" => "REQUEST_CHANGES",
        _ => "COMMENT",
    };

    let gh_review = client
        .submit_review(pr.github_number, event, payload.body.as_deref())
        .await?;

    let now = Utc::now().to_rfc3339();
    db::pr::upsert_review(
        &state.db,
        payload.pr_id,
        &gh_review.user.login,
        &payload.state,
        payload.body.as_deref(),
        Some(gh_review.id),
        gh_review.submitted_at.as_deref().or(Some(&now)),
    )
    .await?;

    Ok(())
}

// ─── pr_merge ────────────────────────────────────────────────────────────────

/// PR をマージする。
#[tauri::command]
pub async fn pr_merge(
    project_id: i64,
    pr_id: i64,
    merge_method: Option<String>,
    state: State<'_, AppState>,
) -> std::result::Result<(), AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let pr = db::pr::find(&state.db, pr_id).await?;
    let token = keychain::require_token(project_id)?;
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);

    let method = merge_method.as_deref().unwrap_or("squash");
    client
        .merge_pull_request(pr.github_number, None, method)
        .await?;

    // ローカル DB を merged に更新
    let now = Utc::now().to_rfc3339();
    sqlx::query(
        "UPDATE pull_requests SET state = 'merged', merged_at = ?, synced_at = ? WHERE id = ?",
    )
    .bind(&now)
    .bind(&now)
    .bind(pr_id)
    .execute(&state.db)
    .await?;

    Ok(())
}

// ─── pr_create_from_branch ───────────────────────────────────────────────────

/// ブランチから GitHub PR を作成して DB に保存する。
#[tauri::command]
pub async fn pr_create_from_branch(
    project_id: i64,
    branch_name: String,
    title: String,
    body: Option<String>,
    state: State<'_, AppState>,
) -> std::result::Result<PullRequest, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let token = keychain::require_token(project_id)?;
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);

    let gh_pr = client
        .create_pull_request(&title, &branch_name, &project.default_branch, body.as_deref())
        .await?;

    let now = Utc::now().to_rfc3339();
    db::pr::upsert(&state.db, project_id, &gh_pr, &now).await?;

    // 作成した PR を返す
    let prs = db::pr::list(&state.db, project_id, None).await?;
    prs.into_iter()
        .find(|p| p.github_number == gh_pr.number)
        .ok_or_else(|| AppError::NotFound("created PR not found in DB".to_string()))
}

// ─── pr_doc_diff_get ─────────────────────────────────────────────────────────

/// PR の .md ファイルのみの unified diff を返す（Design Docs タブ用）。
/// GitHub API GET /pulls/{n}/files → .md フィルタ → unified diff 文字列として返す。
/// parseDiff（TypeScript側）がそのまま処理できる形式。
#[tauri::command]
pub async fn pr_doc_diff_get(
    project_id: i64,
    pr_id: i64,
    state: State<'_, AppState>,
) -> std::result::Result<String, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let pr = db::pr::find(&state.db, pr_id).await?;
    let token = keychain::require_token(project_id)?;
    let client = GitHubClient::new(&token, &project.repo_owner, &project.repo_name);

    let files = client.list_pull_request_files(pr.github_number).await?;

    // .md ファイルのみ抽出して unified diff 文字列を組み立てる
    let diff = build_doc_diff(&files);
    Ok(diff)
}

/// `PrFile` リストから .md ファイルのみを抽出し、unified diff 形式の文字列を組み立てる。
/// parseDiff が処理できるよう `diff --git a/{path} b/{path}` ヘッダを付与する。
pub(crate) fn build_doc_diff(files: &[crate::models::pr::PrFile]) -> String {
    let mut out = String::new();
    for f in files {
        if !f.filename.ends_with(".md") {
            continue;
        }
        // diff ヘッダ
        out.push_str(&format!(
            "diff --git a/{} b/{}\n--- a/{}\n+++ b/{}\n",
            f.filename, f.filename, f.filename, f.filename
        ));
        // patch（hunks）
        if let Some(patch) = &f.patch {
            out.push_str(patch);
            out.push('\n');
        }
    }
    out
}

// ─── git_pull ─────────────────────────────────────────────────────────────────

/// ローカルリポジトリを fetch + fast-forward pull する。
/// コンフリクト発生時は conflict_files テーブルに登録して "conflict" を返す。
/// 戻り値: "success" | "up_to_date" | "conflict"
#[tauri::command]
pub async fn git_pull(
    project_id: i64,
    app: AppHandle,
    state: State<'_, AppState>,
) -> std::result::Result<String, AppError> {
    let project = db::project::find(&state.db, project_id).await?;
    let local_path = project.local_path.clone();
    let token = keychain::require_token(project_id)?;

    let (status, conflict_files) = tokio::task::spawn_blocking(
        move || -> std::result::Result<(PullStatus, Vec<String>), AppError> {
            let git = crate::services::git::GitService::open(&local_path)?;
            let branch = git.current_branch()?;
            let result = git.pull(&token, "origin", &branch)?;
            let files = if result.status == PullStatus::Conflict {
                git.list_conflicted_files().unwrap_or_default()
            } else {
                vec![]
            };
            Ok((result.status, files))
        },
    )
    .await
    .map_err(|e| AppError::Internal(e.to_string()))??;

    // コンフリクト発生時は DB に記録
    if status == PullStatus::Conflict {
        // 既存レコードをクリアして新規登録
        db::conflict::delete_all(&state.db, project_id).await.ok();
        for path in &conflict_files {
            let is_managed = path.ends_with(".md");
            db::conflict::upsert(&state.db, project_id, path, is_managed)
                .await
                .ok();
        }
    }

    let has_conflicts = status == PullStatus::Conflict;
    let _ = app.emit(
        "git_pull_done",
        serde_json::json!({ "project_id": project_id, "has_conflicts": has_conflicts }),
    );

    Ok(match status {
        PullStatus::Success => "success",
        PullStatus::UpToDate => "up_to_date",
        PullStatus::Conflict => "conflict",
    }
    .to_string())
}

