#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ConflictBlock {
    pub index: usize,
    pub ours: String,
    pub theirs: String,
}

/// フロントエンドから受け取る解消指示
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockResolutionInput {
    pub block_index: usize,
    pub resolution: String, // "ours" | "theirs" | "manual"
    pub manual_content: Option<String>,
}

