use crate::error::{AppError, Result};
use reqwest::Client;
use tauri::{AppHandle, Emitter};

pub struct AnthropicClient {
    api_key: String,
    http: Client,
}

impl AnthropicClient {
    pub fn new(api_key: &str) -> Self {
        Self {
            api_key: api_key.to_string(),
            http: Client::new(),
        }
    }

    /// Anthropic Messages API をストリーミングで呼び出し、
    /// テキストデルタごとに `issue_draft_chunk` イベントを emit する。
    /// 最終的に連結した全文を返す。
    pub async fn complete_stream(
        &self,
        system_prompt: &str,
        user_message: &str,
        app: &AppHandle,
        draft_id: i64,
    ) -> Result<String> {
        let body = serde_json::json!({
            "model": "claude-sonnet-4-20250514",
            "max_tokens": 4096,
            "stream": true,
            "system": system_prompt,
            "messages": [
                { "role": "user", "content": user_message }
            ]
        });

        let resp = self
            .http
            .post("https://api.anthropic.com/v1/messages")
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("Content-Type", "application/json")
            .json(&body)
            .send()
            .await
            .map_err(|e| AppError::Anthropic(e.to_string()))?;

        if !resp.status().is_success() {
            let status = resp.status();
            let text = resp
                .text()
                .await
                .unwrap_or_else(|_| "unknown".to_string());
            return Err(AppError::Anthropic(format!(
                "Anthropic API returned {}: {}",
                status, text
            )));
        }

        let mut full_text = String::new();
        let mut stream = resp.bytes_stream();

        use futures_util::StreamExt;
        let mut buf = String::new();

        while let Some(chunk) = stream.next().await {
            let chunk = chunk.map_err(|e| AppError::Anthropic(e.to_string()))?;
            buf.push_str(&String::from_utf8_lossy(&chunk));

            // Process complete SSE lines from the buffer
            while let Some(newline_pos) = buf.find('\n') {
                let line = buf[..newline_pos].to_string();
                buf = buf[newline_pos + 1..].to_string();

                let line = line.trim();
                if !line.starts_with("data: ") {
                    continue;
                }
                let data = &line[6..];
                if data == "[DONE]" {
                    continue;
                }

                if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(data) {
                    if parsed.get("type").and_then(|t| t.as_str()) == Some("content_block_delta")
                    {
                        if let Some(delta_text) = parsed
                            .get("delta")
                            .and_then(|d| d.get("text"))
                            .and_then(|t| t.as_str())
                        {
                            full_text.push_str(delta_text);
                            let _ = app.emit(
                                "issue_draft_chunk",
                                serde_json::json!({
                                    "draft_id": draft_id,
                                    "delta": delta_text,
                                }),
                            );
                        }
                    }
                }
            }
        }

        Ok(full_text)
    }

    /// Anthropic Messages API を非ストリーミングで呼び出し、完全なテキストを返す。
    /// レビュー・コード生成など、一度に全文が必要な場合に使用する。
    pub async fn complete(&self, system_prompt: &str, user_message: &str) -> Result<String> {
        let body = serde_json::json!({
            "model": "claude-sonnet-4-20250514",
            "max_tokens": 8192,
            "system": system_prompt,
            "messages": [
                { "role": "user", "content": user_message }
            ]
        });

        let resp = self
            .http
            .post("https://api.anthropic.com/v1/messages")
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("Content-Type", "application/json")
            .json(&body)
            .send()
            .await
            .map_err(|e| AppError::Anthropic(e.to_string()))?;

        if !resp.status().is_success() {
            let status = resp.status();
            let text = resp.text().await.unwrap_or_else(|_| "unknown".to_string());
            return Err(AppError::Anthropic(format!(
                "Anthropic API returned {}: {}",
                status, text
            )));
        }

        let json: serde_json::Value = resp
            .json()
            .await
            .map_err(|e| AppError::Anthropic(format!("Parse error: {}", e)))?;

        let text = json
            .get("content")
            .and_then(|c| c.as_array())
            .and_then(|arr| arr.first())
            .and_then(|item| item.get("text"))
            .and_then(|t| t.as_str())
            .unwrap_or("")
            .to_string();

        Ok(text)
    }
}

/// Markdown ドキュメントをセクション単位でチャンクに分割する。
/// `##`（level-2）見出しで区切り、最大 ~600 chars 程度を目安とする。

#[derive(Debug, Clone)]
pub struct Chunk {
    pub chunk_index: usize,
    pub section_heading: Option<String>,
    pub content: String,
    pub start_line: usize,
    pub end_line: usize,
}

/// Markdown コンテンツをチャンク配列に変換する。
pub fn chunk_document(content: &str) -> Vec<Chunk> {
    let mut chunks: Vec<Chunk> = Vec::new();
    let mut current_heading: Option<String> = None;
    let mut current_lines: Vec<&str> = Vec::new();
    let mut current_start: usize = 1;
    const MAX_CHARS: usize = 600;

    let lines: Vec<&str> = content.lines().collect();

    for (i, line) in lines.iter().enumerate() {
        let line_no = i + 1;
        let is_heading = line.starts_with("## ") || line.starts_with("# ");

        if is_heading {
            // 現在バッファを flush
            if !current_lines.is_empty() {
                flush_chunk(
                    &mut chunks,
                    &current_heading,
                    &current_lines,
                    current_start,
                    line_no - 1,
                    MAX_CHARS,
                );
                current_lines.clear();
            }
            current_heading = Some(line.to_string());
            current_start = line_no;
            current_lines.push(line);
        } else {
            current_lines.push(line);
        }
    }

    // 末尾 flush
    if !current_lines.is_empty() {
        flush_chunk(
            &mut chunks,
            &current_heading,
            &current_lines,
            current_start,
            lines.len(),
            MAX_CHARS,
        );
    }

    // chunk_index を振り直す
    for (i, c) in chunks.iter_mut().enumerate() {
        c.chunk_index = i;
    }

    chunks
}

/// バッファをチャンクに変換。MAX_CHARS を超える場合はさらに分割する。
fn flush_chunk(
    out: &mut Vec<Chunk>,
    heading: &Option<String>,
    lines: &[&str],
    start_line: usize,
    end_line: usize,
    max_chars: usize,
) {
    let full = lines.join("\n");
    if full.trim().is_empty() {
        return;
    }

    // chars が max_chars 以内なら 1 チャンク
    if full.len() <= max_chars {
        out.push(Chunk {
            chunk_index: 0,
            section_heading: heading.clone(),
            content: full,
            start_line,
            end_line,
        });
        return;
    }

    // 段落（空行）で分割してさらに細かくする
    let mut buf = String::new();
    let mut sub_start = start_line;
    let mut line_cursor = start_line;

    for line in lines {
        line_cursor += 1;
        if line.is_empty() && buf.len() >= max_chars {
            if !buf.trim().is_empty() {
                out.push(Chunk {
                    chunk_index: 0,
                    section_heading: heading.clone(),
                    content: buf.trim().to_string(),
                    start_line: sub_start,
                    end_line: line_cursor - 1,
                });
            }
            buf.clear();
            sub_start = line_cursor;
        } else {
            if !buf.is_empty() {
                buf.push('\n');
            }
            buf.push_str(line);
        }
    }
    if !buf.trim().is_empty() {
        out.push(Chunk {
            chunk_index: 0,
            section_heading: heading.clone(),
            content: buf.trim().to_string(),
            start_line: sub_start,
            end_line,
        });
    }
}

